import React, { useEffect, useState } from 'react';
import { Helmet } from 'react-helmet';
import styled, { createGlobalStyle } from 'styled-components';
import '@fontsource/jost/400.css';
import '@fontsource/jost/600.css';
import '@fontsource/jost/700.css';
import stories from '../data/madlibs';

const STORAGE_KEY = 'madlibs-group-game-v1';
const MIN_GROUP_SIZE = 4;
const MAX_GROUP_SIZE = 6;
const PROMPTS_PER_ROUND = 5;

const takeRandomMembers = (candidateMembers, participantCount) => {
  const selectedMembers = [];

  for (let index = 0; index < participantCount; index += 1) {
    const availableMembers = [...candidateMembers];
    const randomMember = availableMembers[
      Math.floor(Math.random() * availableMembers.length)
    ];
    candidateMembers.delete(randomMember);
    selectedMembers.push(randomMember);
  }

  return selectedMembers;
};

const assignPromptParticipants = (memberCount, prompts) => {
  const allMembers = new Set(Array.from({ length: memberCount }, (_, index) => index));
  let candidateMembers = new Set(allMembers);

  return Object.fromEntries(prompts.map((prompt) => {
    if (!prompt.participantCount) {
      return [prompt.id, null];
    }

    if (prompt.participantCount <= candidateMembers.size) {
      return [prompt.id, takeRandomMembers(candidateMembers, prompt.participantCount)];
    }

    const nextCycleMembers = new Set(
      [...allMembers].filter((member) => !candidateMembers.has(member))
    );
    const selectedMembers = takeRandomMembers(
      candidateMembers,
      candidateMembers.size
    );
    candidateMembers = nextCycleMembers;

    return [
      prompt.id,
      selectedMembers.concat(
        takeRandomMembers(
          candidateMembers,
          prompt.participantCount - selectedMembers.length
        )
      ),
    ];
  }));
};

const renderStory = (template, answers) =>
  template.split(/(\{\{[a-zA-Z][a-zA-Z0-9]*\}\})/).map((part, index) => {
    const placeholder = part.match(/^\{\{([a-zA-Z][a-zA-Z0-9]*)\}\}$/);

    return placeholder ? (
      <Answer key={index}>{answers[placeholder[1]]}</Answer>
    ) : (
      part
    );
  });

const readSavedGame = () => {
  if (typeof window === 'undefined') {
    return null;
  }

  try {
    const saved = window.localStorage.getItem(STORAGE_KEY);
    const game = saved ? JSON.parse(saved) : null;
    const story = game && stories[game.storyIndex];

    const hasValidGroup = game &&
      Array.isArray(game.groupNames) &&
      game.groupNames.length >= MIN_GROUP_SIZE &&
      game.groupNames.length <= MAX_GROUP_SIZE;
    const hasValidAnswers = game &&
      game.answers &&
      typeof game.answers === 'object' &&
      story?.prompts.every((prompt) => typeof game.answers[prompt.id] === 'string') &&
      Number.isInteger(game.currentRound);
    const hasValidPromptParticipants = game &&
      game.promptParticipants &&
      typeof game.promptParticipants === 'object' &&
      story?.prompts.every((prompt) => {
        const participantCount = prompt.participantCount;
        const participants = game.promptParticipants[prompt.id];
        const hasUniqueValidMembers = Array.isArray(participants) &&
          new Set(participants).size === participants.length &&
          participants.every(
            (member) => Number.isInteger(member) && member >= 0 && member < game.groupNames.length
          );

        return participantCount
          ? hasUniqueValidMembers && participants.length === participantCount
          : participants === null;
      });

    if (
      !game ||
      !Number.isInteger(game.storyIndex) ||
      !story ||
      !hasValidGroup ||
      (game.screen !== 'names' && (!hasValidAnswers || !hasValidPromptParticipants))
    ) {
      return null;
    }

    return game;
  } catch (error) {
    return null;
  }
};

const MadlibsPage = () => {
  const [savedGame, setSavedGame] = useState(null);
  const [game, setGame] = useState(null);
  const [screen, setScreen] = useState('welcome');
  const [isReady, setIsReady] = useState(false);

  useEffect(() => {
    setSavedGame(readSavedGame());
    setIsReady(true);
  }, []);

  useEffect(() => {
    if (!isReady || !game || screen === 'welcome') {
      return;
    }

    try {
      window.localStorage.setItem(
        STORAGE_KEY,
        JSON.stringify({
          ...game,
          screen,
          savedAt: new Date().toISOString(),
        })
      );
      setSavedGame({ ...game, screen });
    } catch (error) {
      // The game remains usable if a browser blocks local storage.
    }
  }, [game, isReady, screen]);

  const chooseStory = (storyIndex) => {
    setGame({
      storyIndex,
      groupNames: Array(MIN_GROUP_SIZE).fill(''),
    });
    setScreen('names');
  };

  const updateGroupName = (index, value) => {
    const groupNames = [...game.groupNames];
    groupNames[index] = value;
    setGame({ ...game, groupNames });
  };

  const addGroupMember = () => {
    if (game.groupNames.length < MAX_GROUP_SIZE) {
      setGame({ ...game, groupNames: [...game.groupNames, ''] });
    }
  };

  const removeGroupMember = () => {
    if (game.groupNames.length > MIN_GROUP_SIZE) {
      setGame({ ...game, groupNames: game.groupNames.slice(0, -1) });
    }
  };

  const beginGame = (event) => {
    event.preventDefault();
    if (game.groupNames.some((name) => !name.trim())) {
      return;
    }

    const groupNames = game.groupNames.map((name) => name.trim());
    const story = stories[game.storyIndex];
    const promptParticipants = assignPromptParticipants(
      groupNames.length,
      story.prompts
    );

    setGame({
      ...game,
      groupNames,
      promptParticipants,
      answers: Object.fromEntries(story.prompts.map((prompt) => [prompt.id, ''])),
      currentRound: 0,
    });
    setScreen('play');
  };

  const resumeGame = () => {
    setGame(savedGame);
    setScreen(
      savedGame.screen === 'reveal'
        ? 'reveal'
        : savedGame.screen === 'names'
          ? 'names'
          : 'play'
    );
  };

  const resetGame = () => {
    try {
      window.localStorage.removeItem(STORAGE_KEY);
    } catch (error) {
      // The visual state still resets when local storage is unavailable.
    }
    setSavedGame(null);
    setGame(null);
    setScreen('welcome');
  };

  const updateAnswer = (promptId, answer) => {
    const answers = { ...game.answers, [promptId]: answer };
    setGame({ ...game, answers });
  };

  const nextRound = (event) => {
    event.preventDefault();
    const firstPrompt = game.currentRound * PROMPTS_PER_ROUND;
    const roundPrompts = stories[game.storyIndex].prompts.slice(
      firstPrompt,
      firstPrompt + PROMPTS_PER_ROUND
    );

    if (roundPrompts.some((prompt) => !game.answers[prompt.id].trim())) {
      return;
    }

    if (firstPrompt + PROMPTS_PER_ROUND === stories[game.storyIndex].prompts.length) {
      setScreen('reveal');
      return;
    }

    setGame({ ...game, currentRound: game.currentRound + 1 });
  };

  const previousRound = () => {
    if (game.currentRound > 0) {
      setGame({ ...game, currentRound: game.currentRound - 1 });
    }
  };

  const story = game ? stories[game.storyIndex] : null;
  const roundNumber = game ? game.currentRound + 1 : 0;
  const totalRounds = game ? story.prompts.length / PROMPTS_PER_ROUND : 0;
  const progress = game
    ? (roundNumber / totalRounds) * 100
    : 0;

  return (
    <>
      <PageStyle />
      <Helmet>
        <html lang="en" />
        <title>Table Tales | Group Madlibs</title>
        <meta
          name="description"
          content="A conversation-first Madlib game for groups."
        />
        <meta name="theme-color" content="#f7b267" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
      </Helmet>
      <App>
        <Main>
          <Brand aria-label="Table Tales">
            <Mark aria-hidden="true">✦</Mark>
            <span>Table Tales</span>
          </Brand>

          {screen === 'welcome' && (
            <WelcomeCard>
              <Eyebrow>Group Madlibs</Eyebrow>
              <Title>Turn conversation into a story.</Title>
              <Lead>
                Gather 4-6 people, choose one person to type, and build a
                wonderfully strange tale together.
              </Lead>
              <RuleList>
                <li>Discuss each prompt before writing one shared answer.</li>
                <li>Choose a quick two-round warm-up or a six-round full tale.</li>
              </RuleList>
              <StoryChoices aria-label="Choose a story">
                {stories.map((storyOption, index) => (
                  <StoryChoice key={storyOption.title}>
                    <div>
                      <strong>{storyOption.title}</strong>
                      <span>{storyOption.intro}</span>
                    </div>
                    <ChoiceButton type="button" onClick={() => chooseStory(index)}>
                      Choose <span aria-hidden="true">→</span>
                    </ChoiceButton>
                  </StoryChoice>
                ))}
              </StoryChoices>
              {isReady && savedGame && (
                <ResumeBox>
                  <div>
                    <strong>Welcome back</strong>
                    <span>
                      {stories[savedGame.storyIndex].title} is waiting for
                      your group.
                    </span>
                  </div>
                  <SecondaryButton type="button" onClick={resumeGame}>
                    Resume
                  </SecondaryButton>
                </ResumeBox>
              )}
            </WelcomeCard>
          )}

          {screen === 'names' && game && (
            <SetupCard>
              <Eyebrow>{stories[game.storyIndex].title}</Eyebrow>
              <SetupTitle>Who is at the table?</SetupTitle>
              <Lead>
                Add 4–6 first names. Some prompts will invite specific people
                to answer together. This tale has{' '}
                {stories[game.storyIndex].prompts.length / PROMPTS_PER_ROUND} rounds.
              </Lead>
              <NameForm onSubmit={beginGame}>
                {game.groupNames.map((name, index) => (
                  <NameField key={index}>
                    <label htmlFor={`group-member-${index}`}>
                      Member {index + 1}
                    </label>
                    <input
                      id={`group-member-${index}`}
                      value={name}
                      onChange={(event) => updateGroupName(index, event.target.value)}
                      placeholder={`Name ${index + 1}`}
                      autoComplete="given-name"
                      autoFocus={index === 0}
                      required
                    />
                  </NameField>
                ))}
                <MemberControls>
                  <button
                    type="button"
                    onClick={removeGroupMember}
                    disabled={game.groupNames.length === MIN_GROUP_SIZE}
                  >
                    Remove person
                  </button>
                  <button
                    type="button"
                    onClick={addGroupMember}
                    disabled={game.groupNames.length === MAX_GROUP_SIZE}
                  >
                    Add person
                  </button>
                </MemberControls>
                <ActionRow>
                  <BackButton type="button" onClick={resetGame}>
                    Back
                  </BackButton>
                  <PrimaryButton type="submit">
                    Start round one <span aria-hidden="true">→</span>
                  </PrimaryButton>
                </ActionRow>
              </NameForm>
            </SetupCard>
          )}

          {screen === 'play' && game && (
            <GameCard>
              <GameHeader>
                <div>
                  <Eyebrow>{story.title}</Eyebrow>
                  <GameIntro>{story.intro}</GameIntro>
                </div>
                <Counter>
                  {roundNumber} <span>/ {totalRounds}</span>
                </Counter>
              </GameHeader>
              <Progress aria-label={`Round ${roundNumber} of ${totalRounds}`}>
                <ProgressFill style={{ width: `${progress}%` }} />
              </Progress>
              <PromptForm onSubmit={nextRound}>
                <RoundLabel>Round {roundNumber}: five prompts</RoundLabel>
                {story.prompts
                  .slice(
                    game.currentRound * PROMPTS_PER_ROUND,
                    (game.currentRound + 1) * PROMPTS_PER_ROUND
                  )
                  .map((prompt, index) => {
                    const selectedMembers = prompt.participantCount
                      ? game.promptParticipants[prompt.id]
                      : null;

                    return (
                      <PromptGroup key={prompt.id}>
                        <PromptLabel htmlFor={`madlib-answer-${prompt.id}`}>
                          {selectedMembers
                            ? selectedMembers.map((member, memberIndex) => (
                              <React.Fragment key={member}>
                                {memberIndex > 0 &&
                                  (memberIndex === selectedMembers.length - 1
                                    ? selectedMembers.length === 2
                                      ? ' and '
                                      : ', and '
                                    : ', ')}
                                <SelectedMember>{game.groupNames[member]}</SelectedMember>
                              </React.Fragment>
                            ))
                            : 'Everyone'}{' '}
                          choose:
                        </PromptLabel>
                        <Prompt>{prompt.text}</Prompt>
                        <TextInput
                          id={`madlib-answer-${prompt.id}`}
                          value={game.answers[prompt.id]}
                          onChange={(event) => updateAnswer(prompt.id, event.target.value)}
                          placeholder="Your group’s answer"
                          autoComplete="off"
                          autoFocus={index === 0}
                          required
                        />
                      </PromptGroup>
                    );
                  })}
                <ActionRow>
                  <BackButton
                    type="button"
                    onClick={previousRound}
                    disabled={game.currentRound === 0}
                  >
                    Previous round
                  </BackButton>
                  <PrimaryButton type="submit">
                    {roundNumber === totalRounds
                      ? 'Reveal our tale'
                      : 'Next round'}{' '}
                    <span aria-hidden="true">→</span>
                  </PrimaryButton>
                </ActionRow>
              </PromptForm>
              <PersistenceNote>
                Saved automatically on this device.
              </PersistenceNote>
            </GameCard>
          )}

          {screen === 'reveal' && game && (
            <RevealCard>
              <Eyebrow>Your completed tale</Eyebrow>
              <Title>{story.title}</Title>
              <StoryText>{renderStory(story.template, game.answers)}</StoryText>
              <Celebration>Made by your table. Nicely done.</Celebration>
              <ActionRow>
                <PrimaryButton type="button" onClick={resetGame}>
                  Choose another <span aria-hidden="true">→</span>
                </PrimaryButton>
              </ActionRow>
            </RevealCard>
          )}
        </Main>
        {screen !== 'welcome' && (
          <Footer>
            <button type="button" onClick={resetGame}>
              Start over
            </button>
          </Footer>
        )}
      </App>
    </>
  );
};

export default MadlibsPage;

